"""Shared Hugging Face dataset-card generation for public dataset outputs."""

from __future__ import annotations

import argparse
import json
from collections.abc import Iterable, Mapping
from pathlib import Path
from typing import Any


HF_DATA_FILES_YAML = """---
configs:
- config_name: default
  data_files:
  - split: train
    path: data/*.jsonl
---
"""


